CREATE VIEW `ads_sensors_cd_video_itemclick_big_dipper_view` (`dt` COMMENT "日期", `id` COMMENT "主键", `rid` COMMENT "记录ID", `track_id` COMMENT "track_id", `event` COMMENT "事件", `event_tm` COMMENT "事件时间", `app_channel` COMMENT "渠道编号", `app_id` COMMENT "app_id", `app_lang_id` COMMENT "界面语言", `device_lang` COMMENT "设备语言", `login_id` COMMENT "用户ID", `product_id` COMMENT "产品ID", `app_version` COMMENT "应用版本", `os` COMMENT "操作系统", `core` COMMENT "core版本，目前有1，2，3", `current_language2` COMMENT "注册时语言", `ip` COMMENT "IP", `city` COMMENT "城市", `province` COMMENT "省份", `country` COMMENT "国家", `lib`, `page_name` COMMENT "页面名称", `element_id` COMMENT "控件ID：当页面有下钻控件时上报，目前榜单集合/浏览历史/我的追剧", `element_name` COMMENT "控件名称：当页面有下钻控件时上报，目前榜单集合/浏览历史/我的追剧", `shortplay_id` COMMENT "短剧ID：整部短剧的ID", `is_shortplayshelf` COMMENT "短剧是否已在追剧中：若短剧已主动加入追剧页面记录为1-是，不在为0-否", `element_type` COMMENT "控件类型：只有运营位为控件或特殊对象时记录，例如：普通弹窗、底部弹窗等", `channel_id` COMMENT "频道id：在首页里不同频道分页id", `channel_id1` COMMENT "新频道id", `channel_name` COMMENT "频道名称：在首页里不同频道分页名称：找剧 /发现", `list_id` COMMENT "榜单id：从后台获取榜单id", `list_id1` COMMENT "新榜单id", `send_id` COMMENT "转换来源", `list_style` COMMENT "榜单样式：从后台获取榜单id的“榜单样式”", `list_name` COMMENT "榜单名称：热播短剧/主编力荐/人气排行等", `list_index` COMMENT "榜单位序：用户看到的榜单信息中的位序", `activity_id` COMMENT "活动id", `event_strategy_id` COMMENT "策略id", `group_id` COMMENT "用户分组id", `keyword` COMMENT "搜索词：搜索结果页面上报", `search_mode` COMMENT "搜索方式：{1：主动搜索，2：猜你想搜，3：历史搜索} 根据上次搜索方式上报，搜索结果页面上报", `search_hit_type` COMMENT "搜索命中方式", `project_id` COMMENT "5阅读 8 短剧", `etl_tm` COMMENT "清洗时间") AS SELECT `ods_log`.`a`.`dt`, `ods_log`.`a`.`id`, `ods_log`.`a`.`rid`, `ods_log`.`a`.`track_id`, `ods_log`.`a`.`event`, `ods_log`.`a`.`event_tm`, `ods_log`.`a`.`app_channel`, `ods_log`.`a`.`app_id`, `ods_log`.`a`.`app_lang_id`, `ods_log`.`a`.`device_lang`, `ods_log`.`a`.`login_id`, `ods_log`.`a`.`product_id`, `ods_log`.`a`.`app_version`, `ods_log`.`a`.`os`, CAST((substring(`ods_log`.`a`.`app_id`, 4, 3)) AS INT) AS `core`, `ods`.`b`.`CurrentLanguage2` AS `current_language2`, `ods_log`.`a`.`ip`, `ods_log`.`a`.`city`, `ods_log`.`a`.`province`, `ods_log`.`a`.`country`, `ods_log`.`a`.`lib`, `ods_log`.`a`.`page_name`, `ods_log`.`a`.`element_id`, `ods_log`.`a`.`element_name`, `ods_log`.`a`.`shortplay_id`, `ods_log`.`a`.`is_shortplayshelf`, `ods_log`.`a`.`element_type`, `ods_log`.`a`.`channel_id`, `ods_log`.`a`.`channel_id1`, `ods_log`.`a`.`channel_name`, `ods_log`.`a`.`list_id`, `ods_log`.`a`.`list_id1`, `ods_log`.`a`.`send_id`, `ods_log`.`a`.`list_style`, `ods_log`.`a`.`list_name`, `ods_log`.`a`.`list_index`, `ods_log`.`a`.`activity_id`, `ods_log`.`a`.`event_strategy_id`, `ods_log`.`a`.`group_id`, `ods_log`.`a`.`keyword`, `ods_log`.`a`.`search_mode`, `ods_log`.`a`.`search_hit_type`, `ods_log`.`a`.`project_id`, `ods_log`.`a`.`etl_tm`
FROM `ods_log`.`ods_sensors_cd_video_production_Itemclick_big_dipper` AS `a` LEFT OUTER JOIN `ods`.`ods_tidb_short_video_accountinfo` AS `b` ON `ods_log`.`a`.`login_id` = `ods`.`b`.`Id`
WHERE `ods_log`.`a`.`project_id` = '8';